from random import randint

class Dice:
    __sides = 6

    @classmethod
    def getSides(cls):
        return cls.__sides

    def __init__(self):
        self.__value = randint(1, type(self).getSides())

    @property
    def value(self):
        return self.__value

    def roll(self):
        self.__value = randint(1, type(self).getSides())
